        const data = d.data\(\);
        const bal = parseFloat\(data.financials?.balanceDue\);
        if \(!isNaN\(bal\) && bal > 0\) {
            const startMs = data.startDt?.toDate?.\(\).getTime\(\) || 0;
            withBal.push\({ name: data.customerName, bal, isFuture: startMs >= todayMs }\);
            total += bal;
        }
    }\);
