    console.log\('Total:', total\);
    console.log\('Future only:', withBal.filter\(j=>j.isFuture\).reduce\(\(s,j\)=>s+j.bal,0\)\);
    console.log\('Past only:', withBal.filter\(j=>!j.isFuture\).reduce\(\(s,j\)=>s+j.bal,0\)\);
    console.log\('Sample:', withBal.slice\(0,5\)\);
    process.exit\(0\);
}\);
")

