Bash(node -e "
const admin = require\('firebase-admin'\);
admin.initializeApp\({ projectId: 'installer-portal-6000' }\);
const db = admin.firestore\(\);

const now = new Date\(\);
const monthStart = new Date\(now.getFullYear\(\), now.getMonth\(\), 1\);
const monthEnd = new Date\(now.getFullYear\(\), now.getMonth\(\) + 1, 0, 23, 59, 59\);
const todayMs = new Date\(\).setHours\(0,0,0,0\);

db.collection\('jobs'\).where\('startDt','>=',monthStart\).where\('startDt','<=',monthEnd\).get\(\).then\(snap => {
    const future = snap.docs
        .filter\(d => {
            const bal = parseFloat\(d.data\(\).financials?.balanceDue\);
            const startMs = d.data\(\).startDt?.toDate?.\(\).getTime\(\) || 0;
            return !isNaN\(bal\) && bal > 0 && startMs >= todayMs;
        }\)
        .map\(d => \({ id: d.id, seriesId: d.data\(\).seriesId, bal: parseFloat\(d.data\(\).financials.balanceDue\), name: d.data\(\).customerName }\)\);

    // Find duplicates by seriesId
    const seriesGroups = {};
    future.forEach\(j => {
        if \(j.seriesId\) {
            if \(!seriesGroups[j.seriesId]\) seriesGroups[j.seriesId] = [];
            seriesGroups[j.seriesId].push\(j\);
        }
    }\);

    const dupes = Object.entries\(seriesGroups\).filter\(\([,jobs]\) => jobs.length > 1\);
    console.log\('Future jobs with balanceDue:', future.length\);
    console.log\('Series groups with multiple events:', dupes.length\);
    dupes.slice\(0,5\).forEach\(\([sid, jobs]\) => {
        console.log\(' seriesId:', sid, '| events:', jobs.length, '| each bal:', jobs[0].bal, '| customer:', jobs[0].name\);
    }\);

    // Calculate overcounted amount
    let overcount = 0;
    dupes.forEach\(\([, jobs]\) => overcount += jobs[0].bal * \(jobs.length - 1\)\);
    console.log\('Overcounted amount \(double-counted series\):', overcount\);
    console.log\('Correct upcoming would be:', future.reduce\(\(s,j\)=>s+j.bal,0\) - overcount\);
    process.exit\(0\);
}\);
")

